(function() {
  // 1. Buscamos TODOS os dados que já tínhamos acumulado até aqui
  // Certifique-se de que 'config_agg33' é o nome do nó de configuração ANTERIOR à busca de produtos
  const dadosAcumulados = $('config_agg33').first()?.json || {}; 

  // 2. Pegamos a saída da I.A.
  const rawOutput = $('AI Agent1').first().json.output;
  const cleanOutput = rawOutput.replace(/```json|```/g, '').trim();

  let productInfo = { id: null, name: "Não identificado" };

  try {
    const parsed = JSON.parse(cleanOutput);
    productInfo = { id: parsed.id, name: parsed.name };
  } catch (e) {
    const idMatch = rawOutput.match(/"id":\s*(\d+)/);
    const nameMatch = rawOutput.match(/"name":\s*"([^"]+)"/);
    productInfo = {
      id: idMatch ? parseInt(idMatch[1]) : null,
      name: nameMatch ? nameMatch[1] : "Não identificado"
    };
  }

  // 3. O SEGREDO: Usamos o Object.assign para JUNTAR os dados antigos com o novo produto
  return Object.assign({}, dadosAcumulados, {
    product_object: productInfo
  });
})()
}}

